#include <bits/stdc++.h>
using namespace std;

int m, n, k;
int a[100005], b[100005], t[100005];
vector<int> p[100005];

bool cmp(int a, int b) {
    return a > b;
}

int main() {
    cin >> m >> n >> k;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    for (int i = 0; i < n; i++) {
        cin >> b[i];
    }
    for (int i = 0; i < n; i++) {
        p[a[i]].push_back(b[i]);
    }
    int t1 = 0, t2 = 0, t3 = 0;
    for (int i = 1; i <= m; i++) {
        sort(p[i].begin(), p[i].end(), cmp);
        int s = 0;
        bool flag = true;
        for (int j = 0; j < p[i].size(); j++) {
            s += p[i][j];
            // printf("--- %d %d\n", j, s);
            if (s >= k) {
                if (j + 1 > t1) {
                    t1 = j + 1;
                    t3 = i;
                }
                t2 += j + 1;
                flag = false;
                break;
            }
        }
        if (flag) {
            cout << -1;
            return 0;
        }
    }
    if (t2 - t1 < t1 - 1) {
        if (n - p[t3].size() < t1 - 1) {
            cout << -1;
            return 0;
        }
        cout << (2 * t1 - 1);
    }
    else {
        cout << t2;
    }
    return 0;
}
